def get_target_for_redirect(target: str, domain: str) -> str:
    from urllib.parse import urlparse, urlunparse

    try:
        parsed = urlparse(target)
    except Exception:
        return f'https://{domain}'

    # Only http/https schemes are considered; otherwise fallback
    if parsed.scheme not in ('http', 'https'):
        return f'https://{domain}'

    netloc = parsed.netloc
    # Remove userinfo if present (e.g., user:pass@host)
    if '@' in netloc:
        _, hostport = netloc.rsplit('@', 1)
    else:
        hostport = netloc

    # Remove port if present
    hostname = hostport.split(':')[0] if ':' in hostport else hostport

    if not hostname:
        return f'https://{domain}'

    hostname = hostname.lower()
    domain_lower = domain.lower()

    # Allow exact domain or any subdomain
    if hostname == domain_lower or hostname.endswith('.' + domain_lower):
        # Force https scheme
        if parsed.scheme != 'https':
            parsed = parsed._replace(scheme='https')
        return urlunparse(parsed)
    else:
        return f'https://{domain}'

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = os.path.realpath(dir_path)
        if not os.path.isdir(base_dir):
            return ''
        target_path = os.path.realpath(os.path.join(base_dir, filename))
        if not target_path.startswith(base_dir):
            return ''
        if not os.path.isfile(target_path):
            return ''
        with open(target_path, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ''

