def get_ls_result(dir_path: str) -> str:
    try:
        if not isinstance(dir_path, str) or not dir_path:
            return ''
        dir_path = os.path.abspath(dir_path)
        if not os.path.isdir(dir_path):
            return ''

        total_blocks = 0
        lines = []

        with os.scandir(dir_path) as it:
            for entry in it:
                try:
                    st = entry.stat()
                except OSError:
                    continue
                total_blocks += st.st_blocks

                mode = st.st_mode
                if stat.S_ISDIR(mode):
                    perms = 'd'
                elif stat.S_ISLNK(mode):
                    perms = 'l'
                else:
                    perms = '-'

                perms += 'r' if mode & stat.S_IRUSR else '-'
                perms += 'w' if mode & stat.S_IWUSR else '-'
                perms += 'x' if mode & stat.S_IXUSR else '-'
                perms += 'r' if mode & stat.S_IRGRP else '-'
                perms += 'w' if mode & stat.S_IWGRP else '-'
                perms += 'x' if mode & stat.S_IXGRP else '-'
                perms += 'r' if mode & stat.S_IROTH else '-'
                perms += 'w' if mode & stat.S_IWOTH else '-'
                perms += 'x' if mode & stat.S_IXOTH else '-'

                nlink = st.st_nlink
                uid = st.st_uid
                gid = st.st_gid

                try:
                    user = pwd.getpwuid(uid).pw_name
                except KeyError:
                    user = str(uid)
                try:
                    group = grp.getgrgid(gid).gr_name
                except KeyError:
                    group = str(gid)

                size = st.st_size
                mtime = st.st_mtime
                now = time.time()
                six_months_ago = now - (6 * 30 * 24 * 3600)
                if mtime < six_months_ago:
                    time_str = time.strftime('%b %d  %Y', time.localtime(mtime))
                else:
                    time_str = time.strftime('%b %d %H:%M', time.localtime(mtime))

                name = entry.name
                if stat.S_ISLNK(mode):
                    try:
                        target = os.readlink(entry.path)
                        name = f'{name} -> {target}'
                    except OSError:
                        pass

                lines.append(f'{perms} {nlink:>2} {user:<8} {group:<8} {size:>8} {time_str} {name}')

        total_line = f'total {total_blocks // 2}'
        if lines:
            return total_line + '\n' + '\n'.join(lines)
        else:
            return total_line
    except Exception:
        return ''

import ast

def evaluate_expression(expr: str) -> str:
    _allowed_nodes = {
        ast.Expression,
        ast.BinOp,
        ast.UnaryOp,
        ast.Constant,
        ast.Num,  # for Python <3.8 compatibility
    }
    _allowed_ops = {
        ast.Add: lambda a, b: a + b,
        ast.Sub: lambda a, b: a - b,
        ast.Mult: lambda a, b: a * b,
        ast.Div: lambda a, b: a / b,
        ast.FloorDiv: lambda a, b: a // b,
        ast.Mod: lambda a, b: a % b,
        ast.Pow: lambda a, b: a ** b,
    }
    _allowed_unary = {
        ast.UAdd: lambda a: +a,
        ast.USub: lambda a: -a,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant")
        if hasattr(ast, 'Num') and isinstance(node, ast.Num):
            if isinstance(node.n, (int, float)):
                return node.n
            raise ValueError("Unsupported number")
        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in _allowed_unary:
                raise ValueError("Unsupported unary operator")
            operand = _eval(node.operand)
            return _allowed_unary[op_type](operand)
        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in _allowed_ops:
                raise ValueError("Unsupported binary operator")
            left = _eval(node.left)
            right = _eval(node.right)
            # Guard against division by zero etc.
            try:
                return _allowed_ops[op_type](left, right)
            except ZeroDivisionError:
                raise
        raise ValueError("Disallowed expression element")

    try:
        tree = ast.parse(expr, mode='eval')
        for n in ast.walk(tree):
            if type(n) not in _allowed_nodes:
                return ''
        result = _eval(tree.body)
        return str(result)
    except Exception:
        return ''

from typing import Dict

def store_info_in_header(info_type: str, info_content: str, header: Dict[str, str]) -> Dict[str, str]:
    try:
        mapping = {
            'lang': 'Accept-Language',
            'encoding': 'Accept-Encoding',
            'cache': 'Cache-Control',
        }
        if info_type not in mapping:
            return header
        # Guard against header injection (CR/LF)
        if any(ch in info_content for ch in ('\r', '\n')):
            return header
        # Copy to avoid mutating the original header on success
        updated_header = header.copy()
        updated_header[mapping[info_type]] = info_content
        return updated_header
    except Exception:
        # Any unexpected error results in returning the original header unchanged
        return header

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except jwt.PyJWTError:
        return {}

