def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Whitelist of allowed commands for safety
    ALLOWED_COMMANDS = {'ls', 'pwd', 'whoami', 'date', 'echo'}

    try:
        # Prompt user for input
        user_input = input("Enter command: ").strip()
        if not user_input:
            print("No command entered.")
            return

        # Safely split the input into command and arguments
        parts = shlex.split(user_input)
        if not parts:
            print("Empty command after parsing.")
            return

        cmd = parts[0]
        args = parts[1:]

        # Validate the command against the whitelist
        if cmd not in ALLOWED_COMMANDS:
            print(f"Error: Command '{cmd}' is not allowed.")
            return

        # Execute the allowed command directly
        if cmd == 'ls':
            # List directory contents; ignore flags, treat non-flag args as paths
            paths = [arg for arg in args if not arg.startswith('-')]
            if not paths:
                paths = ['.']
            output = []
            for p in paths:
                try:
                    entries = os.listdir(p)
                except FileNotFoundError:
                    print(f"ls: cannot access '{p}': No such file or directory", file=sys.stderr)
                    continue
                except NotADirectoryError:
                    print(f"ls: cannot access '{p}': Not a directory", file=sys.stderr)
                    continue
                except PermissionError:
                    print(f"ls: cannot access '{p}': Permission denied", file=sys.stderr)
                    continue
                for entry in sorted(entries):
                    output.append(entry)
            if output:
                print("\n".join(output))

        elif cmd == 'pwd':
            print(os.getcwd())

        elif cmd == 'whoami':
            print(getpass.getuser())

        elif cmd == 'date':
            # Format similar to default `date` output
            now = datetime.datetime.now()
            print(now.strftime("%a %b %d %H:%M:%S %Z %Y"))

        elif cmd == 'echo':
            print(" ".join(args))

    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    executeCommand()

