import ast

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    def _eval(node):
        if isinstance(node, ast.Constant):
            return node.value
        # For compatibility with older Python versions
        if hasattr(ast, 'Num') and isinstance(node, ast.Num):
            return node.n
        if hasattr(ast, 'Str') and isinstance(node, ast.Str):
            return node.s
        if hasattr(ast, 'Bytes') and isinstance(node, ast.Bytes):
            return node.b
        if hasattr(ast, 'NameConstant') and isinstance(node, ast.NameConstant):
            return node.value
        if isinstance(node, ast.List):
            return [_eval(el) for el in node.elts]
        if isinstance(node, ast.Tuple):
            return tuple(_eval(el) for el in node.elts)
        if isinstance(node, ast.Set):
            return {_eval(el) for el in node.elts}
        if isinstance(node, ast.Dict):
            return {_eval(k): _eval(v) for k, v in zip(node.keys, node.values)}
        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            if isinstance(node.op, ast.UAdd):
                return +operand
            if isinstance(node.op, ast.USub):
                return -operand
            if isinstance(node.op, ast.Not):
                return not operand
            if isinstance(node.op, ast.Invert):
                return ~operand
            raise ValueError(f"Unsupported unary operator: {node.op}")
        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            if isinstance(node.op, ast.Add):
                return left + right
            if isinstance(node.op, ast.Sub):
                return left - right
            if isinstance(node.op, ast.Mult):
                return left * right
            if isinstance(node.op, ast.Div):
                return left / right
            if isinstance(node.op, ast.FloorDiv):
                return left // right
            if isinstance(node.op, ast.Mod):
                return left % right
            if isinstance(node.op, ast.Pow):
                return left ** right
            raise ValueError(f"Unsupported binary operator: {node.op}")
        if isinstance(node, ast.Compare):
            left = _eval(node.left)
            for op, right in zip(node.ops, node.comparators):
                right_val = _eval(right)
                if isinstance(op, ast.Eq):
                    result = left == right_val
                elif isinstance(op, ast.NotEq):
                    result = left != right_val
                elif isinstance(op, ast.Lt):
                    result = left < right_val
                elif isinstance(op, ast.LtE):
                    result = left <= right_val
                elif isinstance(op, ast.Gt):
                    result = left > right_val
                elif isinstance(op, ast.GtE):
                    result = left >= right_val
                elif isinstance(op, ast.Is):
                    result = left is right_val
                elif isinstance(op, ast.IsNot):
                    result = left is not right_val
                elif isinstance(op, ast.In):
                    result = left in right_val
                elif isinstance(op, ast.NotIn):
                    result = left not in right_val
                else:
                    raise ValueError(f"Unsupported comparator: {op}")
                if not result:
                    return False
                left = right_val
            return True
        if isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                for value in node.values:
                    if not _eval(value):
                        return False
                return True
            if isinstance(node.op, ast.Or):
                for value in node.values:
                    if _eval(value):
                        return True
                return False
            raise ValueError(f"Unsupported boolean operator: {node.op}")
        if hasattr(ast, 'IfExp') and isinstance(node, ast.IfExp):
            test = _eval(node.test)
            return _eval(node.body) if test else _eval(node.orelse)
        raise ValueError(f"Unsupported expression: {ast.dump(node)}")

    try:
        parsed = ast.parse(inputStr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid syntax: {e}") from e
    return _eval(parsed.body)

