import io

def getPickleData(pickled):
    '''
    Return deserialized data from a pickle string, restricting
    deserialization to safe built‑in types only.
    '''
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be a bytes-like object")

    class _SafeUnpickler(pickle.Unpickler):
        SAFE_BUILTINS = {
            'int', 'float', 'str', 'bytes', 'list', 'tuple',
            'set', 'frozenset', 'dict', 'bool', 'type'
        }

        def find_class(self, module, name):
            # Only allow safe classes from the builtins module
            if module == 'builtins' and name in self.SAFE_BUILTINS:
                return getattr(__builtins__, name)
            # Disallow everything else to prevent arbitrary code execution
            raise pickle.UnpicklingError(
                f"Unsafe class '{module}.{name}' is not permitted"
            )

    # Use BytesIO to treat the pickled bytes as a file‑like object
    file_like = io.BytesIO(pickled)
    return _SafeUnpickler(file_like).load()

